import Foundation

/// The result of a benchmark run generated by the `@Benchmark` macro.
///
/// ```swift
/// @Benchmark(iterations: 1000)
/// func compute() -> Int { 42 }
///
/// let result = benchmark_compute()
/// print(result.mean)   // average time per iteration
/// print(result.min)    // fastest iteration
/// print(result.median) // median time
/// print(result.stddev) // standard deviation
/// ```
public struct BenchmarkMacroResult: Sendable {
    /// The name of the benchmarked function.
    public let functionName: String

    /// Number of iterations run.
    public let iterations: Int

    /// Raw execution times for each iteration, in seconds.
    public let times: [Double]

    /// Creates a benchmark result.
    public init(functionName: String, iterations: Int, times: [Double]) {
        self.functionName = functionName
        self.iterations = iterations
        self.times = times
    }

    /// Minimum execution time across all iterations.
    public var min: Double {
        times.min() ?? 0
    }

    /// Maximum execution time across all iterations.
    public var max: Double {
        times.max() ?? 0
    }

    /// Mean (average) execution time.
    public var mean: Double {
        guard !times.isEmpty else { return 0 }
        return times.reduce(0, +) / Double(times.count)
    }

    /// Median execution time.
    public var median: Double {
        guard !times.isEmpty else { return 0 }
        let sorted = times.sorted()
        let count = sorted.count
        if count % 2 == 0 {
            return (sorted[count / 2 - 1] + sorted[count / 2]) / 2
        } else {
            return sorted[count / 2]
        }
    }

    /// Population standard deviation of execution times.
    public var stddev: Double {
        guard times.count > 1 else { return 0 }
        let m = mean
        let variance = times.reduce(0) { $0 + ($1 - m) * ($1 - m) } / Double(times.count)
        return variance.squareRoot()
    }

    /// Total elapsed time across all iterations.
    public var totalElapsed: Double {
        times.reduce(0, +)
    }
}

extension BenchmarkMacroResult: CustomStringConvertible {
    public var description: String {
        """
        Benchmark: \(functionName)
        Iterations: \(iterations)
        Min: \(String(format: "%.6f", min))s
        Max: \(String(format: "%.6f", max))s
        Mean: \(String(format: "%.6f", mean))s
        Median: \(String(format: "%.6f", median))s
        StdDev: \(String(format: "%.6f", stddev))s
        Total: \(String(format: "%.6f", totalElapsed))s
        """
    }
}
